import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { Lock, User } from 'lucide-react';
import Swal from 'sweetalert2';

export default function Login() {
  const [idCard, setIdCard] = useState('');
  const [pin, setPin] = useState('');
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);

    try {
      const response = await fetch('http://localhost:8000/api/auth/login', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ idCard, pin })
      });

      const data = await response.json();

      if (response.ok) {
        localStorage.setItem('sgs_token', data.access_token);
        localStorage.setItem('sgs_user', JSON.stringify(data.teacher));
        navigate('/hub');
      } else {
        Swal.fire({
          icon: 'error',
          title: 'ล็อกอินไม่สำเร็จ',
          text: data.detail || 'รหัสบัตรประชาชนหรือ PIN ไม่ถูกต้อง',
          confirmButtonColor: '#3b82f6'
        });
      }
    } catch (error) {
      Swal.fire({
        icon: 'error',
        title: 'เกิดข้อผิดพลาด',
        text: 'ไม่สามารถเชื่อมต่อกับเซิร์ฟเวอร์ได้',
        confirmButtonColor: '#3b82f6'
      });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-50 to-indigo-100 flex items-center justify-center p-4">
      <div className="bg-white rounded-2xl shadow-xl w-full max-w-md overflow-hidden">
        <div className="bg-blue-600 p-6 text-center">
          <div className="bg-white/20 w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-4">
            <Lock className="text-white w-8 h-8" />
          </div>
          <h1 className="text-2xl font-bold text-white">TeacherHub</h1>
          <p className="text-blue-100 mt-1">ระบบเข้าสู่ระบบศูนย์กลาง</p>
        </div>

        <form onSubmit={handleLogin} className="p-8">
          <div className="mb-5">
            <label className="block text-sm font-medium text-gray-700 mb-1">รหัสประจำตัวประชาชน (13 หลัก)</label>
            <div className="relative">
              <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                <User className="h-5 w-5 text-gray-400" />
              </div>
              <input 
                type="text" 
                value={idCard}
                onChange={(e) => setIdCard(e.target.value)}
                className="pl-10 w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition"
                placeholder="เลขบัตรประชาชน"
                required
              />
            </div>
          </div>

          <div className="mb-6">
            <label className="block text-sm font-medium text-gray-700 mb-1">รหัสผ่าน (PIN)</label>
            <div className="relative">
              <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                <Lock className="h-5 w-5 text-gray-400" />
              </div>
              <input 
                type="password" 
                value={pin}
                onChange={(e) => setPin(e.target.value)}
                className="pl-10 w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition"
                placeholder="รหัส PIN 4 หลัก"
                required
              />
            </div>
          </div>

          <button 
            type="submit" 
            disabled={loading}
            className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-3 px-4 rounded-lg transition duration-200 shadow-md flex justify-center items-center"
          >
            {loading ? (
              <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
            ) : "เข้าสู่ระบบ"}
          </button>
        </form>
      </div>
    </div>
  );
}

import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import Login from './Login';
import TeacherHub from './TeacherHub';
import SgsNextschoolApp from './SgsNextschoolApp';

function PrivateRoute({ children }: { children: JSX.Element }) {
  const token = localStorage.getItem('sgs_token');
  return token ? children : <Navigate to="/login" />;
}

export default function App() {
  return (
    <Router>
      <Routes>
        <Route path="/login" element={<Login />} />
        <Route 
          path="/hub" 
          element={
            <PrivateRoute>
              <TeacherHub />
            </PrivateRoute>
          } 
        />
        <Route 
          path="/sgs-compare" 
          element={
            <PrivateRoute>
              <SgsNextschoolApp />
            </PrivateRoute>
          } 
        />
        <Route path="*" element={<Navigate to="/hub" />} />
      </Routes>
    </Router>
  );
}

