import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { Lock, User, KeyRound, ChevronRight, School } from 'lucide-react';
import Swal from 'sweetalert2';

export default function Login() {
  const [idCard, setIdCard] = useState('');
  const [pin, setPin] = useState('');
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);

    try {
      const response = await fetch('http://localhost:8000/api/auth/login', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ idCard, pin })
      });

      const data = await response.json();

      if (response.ok) {
        localStorage.setItem('sgs_token', data.access_token);
        localStorage.setItem('sgs_user', JSON.stringify(data.teacher));
        navigate('/hub');
      } else {
        Swal.fire({
          icon: 'error',
          title: 'เข้าสู่ระบบล้มเหลว',
          text: data.detail || 'รหัสประจำตัวประชาชน หรือ PIN ไม่ถูกต้อง',
