        <div className="absolute bottom-[-10%] right-[-10%] w-[60%] h-[60%] rounded-full bg-blue-500/20 blur-[150px] mix-blend-screen animate-pulse duration-[10s] delay-1000" />
        <div className="absolute top-[20%] right-[10%] w-[30%] h-[30%] rounded-full bg-purple-500/20 blur-[100px] mix-blend-screen animate-pulse duration-[6s] delay-2000" />
      </div>

      <div className="relative z-10 w-full max-w-md p-6">
        {/* Glass Card */}
        <div className="bg-white/10 backdrop-blur-xl border border-white/20 shadow-2xl rounded-3xl overflow-hidden transform transition-all duration-500 hover:shadow-indigo-500/20">
          <div className="px-8 pt-10 pb-8 text-center">
            <div className="inline-flex items-center justify-center w-20 h-20 rounded-2xl bg-gradient-to-tr from-indigo-500 to-blue-400 shadow-lg mb-6 transform rotate-3 hover:rotate-6 transition-transform duration-300">
              <School className="w-10 h-10 text-white" />
            </div>
            <h1 className="text-3xl font-extrabold text-white tracking-tight mb-2">TeacherHub</h1>
            <p className="text-indigo-200 text-sm font-medium">เข้าสู่ระบบศูนย์กลางบุคลากร</p>
          </div>

          <form onSubmit={handleLogin} className="px-8 pb-10 space-y-6">
            <div className="space-y-1">
              <label className="block text-xs font-semibold text-indigo-200 uppercase tracking-wider ml-1">เลขประจำตัวประชาชน</label>
              <div className="relative group">
                <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none transition-colors duration-300 group-focus-within:text-indigo-400 text-slate-400">
                  <User className="h-5 w-5" />
                </div>
                <input 
                  type="text" 
                  value={idCard}
                  onChange={(e) => setIdCard(e.target.value)}
                  className="w-full pl-11 pr-4 py-3.5 bg-slate-800/50 border border-slate-700/50 rounded-xl text-white placeholder-slate-500 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all duration-300 shadow-inner"
                  placeholder="กรอกเลขบัตร 13 หลัก"
                  required
                />
              </div>
            </div>

            <div className="space-y-1">
              <label className="block text-xs font-semibold text-indigo-200 uppercase tracking-wider ml-1">รหัส PIN</label>
