import { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { LogOut, ArrowLeft, Users, BarChart3, CheckCircle2, AlertTriangle, Search } from 'lucide-react';

export default function AdminHub() {
  const navigate = useNavigate();
  const [user, setUser] = useState<any>(null);
  const [stats, setStats] = useState<any>(null);
  const [teachers, setTeachers] = useState<any[]>([]);
  const [search, setSearch] = useState('');

  useEffect(() => {
    const token = localStorage.getItem('sgs_token');
    const userData = localStorage.getItem('sgs_user');

    if (!token || !userData) {
      navigate('/login');
      return;
    }

    const parsedUser = JSON.parse(userData);
    if (!parsedUser.is_admin) {
      navigate('/hub'); // Not admin, back to normal hub
      return;
    }

    setUser(parsedUser);

    // Fetch School Stats
    fetch('http://localhost:8000/api/admin/stats')
      .then(res => res.json())
      .then(data => setStats(data));

    // Fetch Teachers list
    fetch('http://localhost:8000/api/admin/teachers')
      .then(res => res.json())
      .then(data => setTeachers(data));

  }, [navigate]);

  if (!user || !stats) return null;

  const filteredTeachers = teachers.filter(t => 
    t.name.includes(search) || t.teaccode.includes(search) || t.subjectgroup.includes(search)
  );

  return (
    <div className="min-h-screen bg-slate-50 font-sans">
      {/* Navbar */}
      <nav className="bg-indigo-900 text-white sticky top-0 z-50 shadow-md">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between items-center h-20">
            <div className="flex items-center gap-4">
              <button onClick={() => navigate('/hub')} className="p-2 bg-indigo-800 rounded-lg hover:bg-indigo-700 transition">
                <ArrowLeft className="w-5 h-5" />
              </button>
              <div>
                <span className="font-extrabold text-2xl tracking-tight flex items-center">
                  <BarChart3 className="mr-2" /> School Dashboard
                </span>
                <p className="text-indigo-200 text-sm font-medium">ระบบผู้ดูแลสำหรับสรุปภาพรวมโรงเรียน</p>
              </div>
            </div>

            <div className="flex items-center gap-6">
              <span className="text-sm font-bold text-indigo-100 hidden md:block">
                Admin: ครู{user.name}
              </span>
              <button 
                onClick={() => {
                  localStorage.clear();
                  navigate('/login');
                }}
                className="flex items-center p-2.5 text-indigo-200 hover:text-white hover:bg-red-500/20 rounded-xl transition-all"
              >
                <LogOut className="h-5 w-5" />
              </button>
            </div>
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">

        {/* Stats Row */}
        <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mb-8">
          <div className="bg-white rounded-2xl p-6 shadow-sm border border-slate-100 flex flex-col justify-between">
            <div className="flex justify-between items-start mb-2">
              <h3 className="text-slate-500 font-semibold text-sm uppercase">จำนวนบุคลากรทั้งหมด</h3>
              <div className="bg-indigo-100 text-indigo-600 p-2 rounded-lg"><Users className="w-5 h-5" /></div>
            </div>
            <div className="text-4xl font-extrabold text-slate-900">{stats.total_teachers}</div>
          </div>

          <div className="bg-white rounded-2xl p-6 shadow-sm border border-slate-100 flex flex-col justify-between">
            <div className="flex justify-between items-start mb-2">
              <h3 className="text-slate-500 font-semibold text-sm uppercase">นักเรียนติด 0, ร, มผ</h3>
              <div className="bg-red-100 text-red-600 p-2 rounded-lg"><AlertTriangle className="w-5 h-5" /></div>
            </div>
            <div className="text-4xl font-extrabold text-slate-900">{stats.total_academic_issues} <span className="text-sm text-slate-400 font-medium">คน</span></div>
          </div>

          <div className="bg-white rounded-2xl p-6 shadow-sm border border-slate-100 flex flex-col justify-between">
            <div className="flex justify-between items-start mb-2">
              <h3 className="text-slate-500 font-semibold text-sm uppercase">ความคืบหน้าส่งคะแนน</h3>
              <div className="bg-amber-100 text-amber-600 p-2 rounded-lg"><BarChart3 className="w-5 h-5" /></div>
            </div>
            <div className="text-4xl font-extrabold text-slate-900">{stats.sgs_progress.percentage}%</div>
            <div className="w-full bg-slate-100 rounded-full h-1.5 mt-3">
              <div className="bg-amber-500 h-1.5 rounded-full" style={{ width: `${stats.sgs_progress.percentage}%` }}></div>
            </div>
            <p className="text-xs text-slate-500 mt-2 text-right">{stats.sgs_progress.submitted} / {stats.sgs_progress.total} วิชา</p>
          </div>

          <div className="bg-white rounded-2xl p-6 shadow-sm border border-slate-100 flex flex-col justify-between">
            <div className="flex justify-between items-start mb-2">
              <h3 className="text-slate-500 font-semibold text-sm uppercase">การประเมิน IOC</h3>
              <div className="bg-emerald-100 text-emerald-600 p-2 rounded-lg"><CheckCircle2 className="w-5 h-5" /></div>
            </div>
            <div className="text-4xl font-extrabold text-slate-900">{stats.ioc_progress.percentage}%</div>
            <div className="w-full bg-slate-100 rounded-full h-1.5 mt-3">
              <div className="bg-emerald-500 h-1.5 rounded-full" style={{ width: `${stats.ioc_progress.percentage}%` }}></div>
            </div>
            <p className="text-xs text-slate-500 mt-2 text-right">{stats.ioc_progress.submitted} / {stats.ioc_progress.total} แผน</p>
          </div>
        </div>

        {/* Teachers List */}
        <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
          <div className="p-6 border-b border-slate-100 flex justify-between items-center">
            <h2 className="text-xl font-bold text-slate-900">รายชื่อบุคลากร</h2>
            <div className="relative">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
              <input 
                type="text" 
                placeholder="ค้นหาชื่อ, รหัส..." 
                className="pl-10 pr-4 py-2 border border-slate-200 rounded-xl text-sm focus:ring-2 focus:ring-indigo-500 outline-none"
                value={search}
                onChange={(e) => setSearch(e.target.value)}
              />
            </div>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-sm text-left">
              <thead className="text-xs text-slate-500 uppercase bg-slate-50 border-b border-slate-100">
                <tr>
                  <th className="px-6 py-4">รหัส</th>
                  <th className="px-6 py-4">ชื่อ - สกุล</th>
                  <th className="px-6 py-4">กลุ่มสาระฯ</th>
                  <th className="px-6 py-4 text-center">บทบาท</th>
                  <th className="px-6 py-4 text-center">จัดการ</th>
                </tr>
              </thead>
              <tbody>
                {filteredTeachers.map((t) => (
                  <tr key={t.id} className="border-b border-slate-50 hover:bg-slate-50/50">
                    <td className="px-6 py-4 font-medium text-slate-900">{t.teaccode}</td>
                    <td className="px-6 py-4">{t.name}</td>
                    <td className="px-6 py-4">{t.subjectgroup}</td>
                    <td className="px-6 py-4 text-center">
                      {t.is_admin ? (
                        <span className="bg-indigo-100 text-indigo-700 px-2 py-1 rounded text-xs font-bold">Admin</span>
                      ) : (
                        <span className="bg-slate-100 text-slate-600 px-2 py-1 rounded text-xs">Teacher</span>
                      )}
                    </td>
                    <td className="px-6 py-4 text-center">
                      <button className="text-indigo-600 hover:underline text-xs font-medium">รีเซ็ตรหัส</button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </main>
    </div>
  );
}

