  const [stats, setStats] = useState<any>(null);
  const [teachers, setTeachers] = useState<any[]>([]);
  const [search, setSearch] = useState('');

  // Add Teacher Modal State
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [newTeacher, setNewTeacher] = useState({
    userid: '', teaccode: '', prefix: '', firstname: '', lastname: '', subjectgroup: ''
  });

  const fetchTeachers = () => {
    fetch('http://localhost:8000/api/admin/teachers')
      .then(res => res.json())
      .then(data => setTeachers(data));
  };

  useEffect(() => {
    const token = localStorage.getItem('sgs_token');
    const userData = localStorage.getItem('sgs_user');

    if (!token || !userData) {
      navigate('/login');
      return;
    }

    const parsedUser = JSON.parse(userData);
    if (!parsedUser.is_admin) {
      navigate('/hub'); // Not admin, back to normal hub
      return;
    }

    setUser(parsedUser);

    // Fetch School Stats
    fetch('http://localhost:8000/api/admin/stats')
      .then(res => res.json())
      .then(data => setStats(data));

    fetchTeachers();

  }, [navigate]);

  const handleAddTeacher = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      const res = await fetch('http://localhost:8000/api/admin/teachers', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(newTeacher)
      });
      const data = await res.json();
      if (res.ok) {
        Swal.fire('สำเร็จ', data.message + `\nรหัสผ่านแรกเข้าคือ: ${data.raw_pin}`, 'success');
