      title: 'ยืนยันการรีเซ็ตรหัสผ่าน',
      text: `คุณต้องการรีเซ็ตรหัสผ่านของครู ${name} กลับเป็นค่าเริ่มต้นใช่หรือไม่?`,
      icon: 'warning',
      showCancelButton: true,
      confirmButtonColor: '#4f46e5',
      cancelButtonColor: '#ef4444',
      confirmButtonText: 'ยืนยัน',
      cancelButtonText: 'ยกเลิก'
    });

    if (result.isConfirmed) {
      try {
        const res = await fetch(`http://localhost:8000/api/admin/teachers/${id}/reset_pin`, { method: 'POST' });
        const data = await res.json();
        if (res.ok) {
          Swal.fire('สำเร็จ', `รีเซ็ตรหัสผ่านสำเร็จ\nรหัสผ่านใหม่คือ: ${data.new_pin}`, 'success');
        } else {
          Swal.fire('เกิดข้อผิดพลาด', data.detail, 'error');
        }
      } catch (err) {
        Swal.fire('เกิดข้อผิดพลาด', 'ไม่สามารถเชื่อมต่อเซิร์ฟเวอร์ได้', 'error');
      }
    }
  };

  if (!user || !stats) return null;

  const filteredTeachers = teachers.filter(t => 
    t.name.includes(search) || t.teaccode.includes(search) || t.subjectgroup.includes(search) || t.userid.includes(search)
  );

  return (
    <div className="min-h-screen bg-slate-50 font-sans relative">
      {/* Navbar */}
      <nav className="bg-indigo-900 text-white sticky top-0 z-50 shadow-md">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between items-center h-20">
            <div className="flex items-center gap-4">
              <button onClick={() => navigate('/hub')} className="p-2 bg-indigo-800 rounded-lg hover:bg-indigo-700 transition">
                <ArrowLeft className="w-5 h-5" />
              </button>
              <div>
                <span className="font-extrabold text-2xl tracking-tight flex items-center">
                  <BarChart3 className="mr-2" /> School Dashboard
                </span>
                <p className="text-indigo-200 text-sm font-medium">ระบบผู้ดูแลสำหรับสรุปภาพรวมโรงเรียน</p>
              </div>
            </div>

            <div className="flex items-center gap-6">
              <span className="text-sm font-bold text-indigo-100 hidden md:block">
                Admin: ครู{user.name}
              </span>
              <button 
                onClick={() => {
                  localStorage.clear();
                  navigate('/login');
                }}
                className="flex items-center p-2.5 text-indigo-200 hover:text-white hover:bg-red-500/20 rounded-xl transition-all"
              >
                <LogOut className="h-5 w-5" />
              </button>
            </div>
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">

        {/* Stats Row */}
        <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mb-8">
          <div className="bg-white rounded-2xl p-6 shadow-sm border border-slate-100 flex flex-col justify-between">
            <div className="flex justify-between items-start mb-2">
              <h3 className="text-slate-500 font-semibold text-sm uppercase">จำนวนบุคลากรทั้งหมด</h3>
              <div className="bg-indigo-100 text-indigo-600 p-2 rounded-lg"><Users className="w-5 h-5" /></div>
            </div>
            <div className="text-4xl font-extrabold text-slate-900">{stats.total_teachers}</div>
          </div>

          <div className="bg-white rounded-2xl p-6 shadow-sm border border-slate-100 flex flex-col justify-between">
            <div className="flex justify-between items-start mb-2">
              <h3 className="text-slate-500 font-semibold text-sm uppercase">นักเรียนติด 0, ร, มผ</h3>
              <div className="bg-red-100 text-red-600 p-2 rounded-lg"><AlertTriangle className="w-5 h-5" /></div>
            </div>
            <div className="text-4xl font-extrabold text-slate-900">{stats.total_academic_issues} <span className="text-sm text-slate-400 font-medium">คน</span></div>
          </div>

          <div className="bg-white rounded-2xl p-6 shadow-sm border border-slate-100 flex flex-col justify-between">
            <div className="flex justify-between items-start mb-2">
              <h3 className="text-slate-500 font-semibold text-sm uppercase">ความคืบหน้าส่งคะแนน</h3>
              <div className="bg-amber-100 text-amber-600 p-2 rounded-lg"><BarChart3 className="w-5 h-5" /></div>
            </div>
            <div className="text-4xl font-extrabold text-slate-900">{stats.sgs_progress.percentage}%</div>
            <div className="w-full bg-slate-100 rounded-full h-1.5 mt-3">
              <div className="bg-amber-500 h-1.5 rounded-full" style={{ width: `${stats.sgs_progress.percentage}%` }}></div>
            </div>
            <p className="text-xs text-slate-500 mt-2 text-right">{stats.sgs_progress.submitted} / {stats.sgs_progress.total} วิชา</p>
          </div>

          <div className="bg-white rounded-2xl p-6 shadow-sm border border-slate-100 flex flex-col justify-between">
            <div className="flex justify-between items-start mb-2">
              <h3 className="text-slate-500 font-semibold text-sm uppercase">การประเมิน IOC</h3>
              <div className="bg-emerald-100 text-emerald-600 p-2 rounded-lg"><CheckCircle2 className="w-5 h-5" /></div>
            </div>
            <div className="text-4xl font-extrabold text-slate-900">{stats.ioc_progress.percentage}%</div>
            <div className="w-full bg-slate-100 rounded-full h-1.5 mt-3">
              <div className="bg-emerald-500 h-1.5 rounded-full" style={{ width: `${stats.ioc_progress.percentage}%` }}></div>
            </div>
            <p className="text-xs text-slate-500 mt-2 text-right">{stats.ioc_progress.submitted} / {stats.ioc_progress.total} แผน</p>
