          <div className="p-6 border-b border-slate-100 flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
            <h2 className="text-xl font-bold text-slate-900">รายชื่อบุคลากร</h2>
            <div className="flex items-center gap-4 w-full md:w-auto">
              <div className="relative flex-1 md:flex-none md:w-64">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                <input 
                  type="text" 
                  placeholder="ค้นหาชื่อ, รหัส..." 
                  className="w-full pl-10 pr-4 py-2 border border-slate-200 rounded-xl text-sm focus:ring-2 focus:ring-indigo-500 outline-none"
                  value={search}
                  onChange={(e) => setSearch(e.target.value)}
                />
              </div>
              <button 
                onClick={() => setIsAddModalOpen(true)}
                className="flex items-center justify-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 transition-colors shadow-sm text-sm font-semibold whitespace-nowrap"
              >
                <Plus className="w-4 h-4" /> เพิ่มครูใหม่
              </button>
            </div>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-sm text-left">
              <thead className="text-xs text-slate-500 uppercase bg-slate-50 border-b border-slate-100">
                <tr>
                  <th className="px-6 py-4">รหัสครู</th>
                  <th className="px-6 py-4">เลขบัตรประชาชน</th>
                  <th className="px-6 py-4">ชื่อ - สกุล</th>
                  <th className="px-6 py-4">กลุ่มสาระฯ</th>
                  <th className="px-6 py-4 text-center">บทบาท</th>
                  <th className="px-6 py-4 text-center">จัดการ</th>
                </tr>
              </thead>
              <tbody>
                {filteredTeachers.map((t) => (
                  <tr key={t.id} className="border-b border-slate-50 hover:bg-slate-50/50">
                    <td className="px-6 py-4 font-bold text-slate-900">{t.teaccode}</td>
                    <td className="px-6 py-4 text-slate-500 font-mono text-xs">{t.userid}</td>
                    <td className="px-6 py-4 font-medium">{t.name}</td>
                    <td className="px-6 py-4">{t.subjectgroup}</td>
                    <td className="px-6 py-4 text-center">
                      {t.is_admin ? (
                        <span className="bg-indigo-100 text-indigo-700 px-2 py-1 rounded text-xs font-bold">Admin</span>
                      ) : (
                        <span className="bg-slate-100 text-slate-600 px-2 py-1 rounded text-xs">Teacher</span>
                      )}
                    </td>
                    <td className="px-6 py-4 text-center">
