                  <input required type="text" maxLength={13} className="w-full px-4 py-2 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none" 
                    value={newTeacher.userid} onChange={e => setNewTeacher({...newTeacher, userid: e.target.value})} placeholder="สำหรับล็อกอิน" />
                </div>

                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">รหัสครู <span className="text-red-500">*</span></label>
                  <input required type="text" className="w-full px-4 py-2 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none" 
                    value={newTeacher.teaccode} onChange={e => setNewTeacher({...newTeacher, teaccode: e.target.value})} placeholder="เช่น 999" />
                </div>

                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">คำนำหน้า <span className="text-red-500">*</span></label>
                  <select required className="w-full px-4 py-2 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
                    value={newTeacher.prefix} onChange={e => setNewTeacher({...newTeacher, prefix: e.target.value})}>
                    <option value="">เลือกคำนำหน้า</option>
                    <option value="นาย">นาย</option>
                    <option value="นาง">นาง</option>
                    <option value="นางสาว">นางสาว</option>
                    <option value="ว่าที่ ร.ต.">ว่าที่ ร.ต.</option>
                  </select>
                </div>

                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">ชื่อ <span className="text-red-500">*</span></label>
                  <input required type="text" className="w-full px-4 py-2 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none" 
                    value={newTeacher.firstname} onChange={e => setNewTeacher({...newTeacher, firstname: e.target.value})} />
                </div>

                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-1">นามสกุล <span className="text-red-500">*</span></label>
                  <input required type="text" className="w-full px-4 py-2 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none" 
                    value={newTeacher.lastname} onChange={e => setNewTeacher({...newTeacher, lastname: e.target.value})} />
                </div>

                <div className="col-span-2">
                  <label className="block text-sm font-semibold text-slate-700 mb-1">กลุ่มสาระฯ</label>
                  <input type="text" className="w-full px-4 py-2 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none" 
                    value={newTeacher.subjectgroup} onChange={e => setNewTeacher({...newTeacher, subjectgroup: e.target.value})} placeholder="เช่น คณิตศาสตร์" />
                </div>
              </div>

              <div className="bg-indigo-50 text-indigo-700 p-4 rounded-xl text-sm mb-6 flex items-start gap-3">
                <AlertTriangle className="w-5 h-5 flex-shrink-0" />
                <p>รหัสผ่าน (PIN) แรกเข้าของครูใหม่จะถูกตั้งเป็น <strong>6 หลักสุดท้ายของเลขประจำตัวประชาชน</strong> โดยอัตโนมัติ</p>
              </div>

              <div className="flex justify-end gap-3">
                <button type="button" onClick={() => setIsAddModalOpen(false)} className="px-5 py-2.5 text-slate-600 font-semibold hover:bg-slate-100 rounded-xl transition-colors">
                  ยกเลิก
                </button>
                <button type="submit" className="px-5 py-2.5 bg-indigo-600 text-white font-semibold hover:bg-indigo-700 rounded-xl transition-colors shadow-md">
                  บันทึกข้อมูล
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

